PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE words (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  word        TEXT    NOT NULL,
  translation TEXT    NOT NULL,
  level       TEXT    NOT NULL CHECK(level IN ('A1','A2','B1','B2','C1','C2')),
  category    TEXT    NOT NULL DEFAULT 'general',
  uk_ipa      TEXT    NOT NULL DEFAULT '',
  us_ipa      TEXT    NOT NULL DEFAULT ''
);
CREATE INDEX idx_words_level     ON words(level);
CREATE INDEX idx_words_level_cat ON words(level, category);
CREATE INDEX idx_words_word      ON words(word);
CREATE UNIQUE INDEX uniq_words_word_level_cat
  ON words(word, level, category);
COMMIT;
